#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, M; scanf("%lld %lld", &N, &M);
        int gRow = (int)((N-1) % 4);
        int gCol = (int)((M-1) % 3);
        if((gRow ^ gCol) != 0) printf("Tuzik\n");
        else printf("Vanya\n");
    }
    return 0;
}

